export async function generateCodeVerifier() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return base64UrlEncode(array);
}

export async function generateCodeChallenge(verifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(verifier);
  const digest = await crypto.subtle.digest('SHA-256', data);
  return base64UrlEncode(new Uint8Array(digest));
}

function base64UrlEncode(buffer) {
  let str = '';
  const bytes = new Uint8Array(buffer);
  for (let i = 0; i < bytes.byteLength; i++) {
    str += String.fromCharCode(bytes[i]);
  }
  return btoa(str).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

export function generateState() {
  const array = new Uint8Array(16);
  crypto.getRandomValues(array);
  return base64UrlEncode(array);
}

export function generateNonce() {
  const array = new Uint8Array(16);
  crypto.getRandomValues(array);
  return base64UrlEncode(array);
}

// --- src/utils/token.js ---
export function decodeJwt(token) {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) {
      throw new Error('Invalid JWT format');
    }
    const header = JSON.parse(atob(parts[0].replace(/-/g, '+').replace(/_/g, '/')));
    const payload = JSON.parse(atob(parts[1].replace(/-/g, '+').replace(/_/g, '/')));
    return { header, payload, signature: parts[2] };
  } catch (e) {
    console.error('Failed to decode JWT:', e);
    return null;
  }
}

export function isTokenExpired(token) {
  const decoded = decodeJwt(token);
  if (!decoded || !decoded.payload.exp) return true;
  const now = Math.floor(Date.now() / 1000);
  return decoded.payload.exp < now;
}

export function validateIdToken(idToken, clientId, nonce) {
  const decoded = decodeJwt(idToken);
  if (!decoded) {
    return { valid: false, error: 'Failed to decode id_token' };
  }

  const { payload } = decoded;

  // Validate audience
  const aud = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
  if (!aud.includes(clientId)) {
    return { valid: false, error: 'Invalid audience in id_token' };
  }

  // Validate expiration
  const now = Math.floor(Date.now() / 1000);
  if (payload.exp && payload.exp < now) {
    return { valid: false, error: 'id_token is expired' };
  }

  // Validate issued at (allow 5 minute clock skew)
  if (payload.iat && payload.iat > now + 300) {
    return { valid: false, error: 'id_token issued in the future' };
  }

  // Validate nonce
  if (nonce && payload.nonce !== nonce) {
    return { valid: false, error: 'Invalid nonce in id_token' };
  }

  return { valid: true, payload };
}

