import React, { createContext, useContext, useState, useEffect, useCallback, useRef } from 'react';
import oidcService from '../services/oidcService.js';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const refreshTimerRef = useRef(null);

  const scheduleTokenRefresh = useCallback((tokens) => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    if (tokens?.expires_in) {
      // Refresh 60 seconds before expiry
      const refreshIn = (tokens.expires_in - 60) * 1000;
      if (refreshIn > 0) {
        refreshTimerRef.current = setTimeout(async () => {
          try {
            const newTokens = await oidcService.refreshTokens();
            const profile = oidcService.getUserProfile();
            setUser(profile);
            scheduleTokenRefresh(newTokens);
          } catch (err) {
            console.error('Token refresh failed:', err);
            setIsAuthenticated(false);
            setUser(null);
          }
        }, refreshIn);
      }
    }
  }, []);

  useEffect(() => {
    // Check if user is already authenticated on mount
    const checkAuth = () => {
      if (oidcService.isAuthenticated()) {
        const profile = oidcService.getUserProfile();
        setUser(profile);
        setIsAuthenticated(true);

        // Schedule refresh if we have token info
        const tokens = oidcService.getAccessToken() ? { expires_in: 3600 } : null;
        if (tokens) scheduleTokenRefresh(tokens);
      }
      setIsLoading(false);
    };

    checkAuth();

    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, [scheduleTokenRefresh]);

  const login = useCallback(async () => {
    try {
      setError(null);
      const authUrl = await oidcService.getAuthorizationUrl();
      window.location.href = authUrl;
    } catch (err) {
      setError(err.message);
      console.error('Login failed:', err);
    }
  }, []);

  const handleCallback = useCallback(async (callbackUrl) => {
    try {
      setIsLoading(true);
      setError(null);
      const tokens = await oidcService.handleCallback(callbackUrl);
      const profile = oidcService.getUserProfile();
      setUser(profile);
      setIsAuthenticated(true);
      scheduleTokenRefresh(tokens);
      return profile;
    } catch (err) {
      setError(err.message);
      setIsAuthenticated(false);
      setUser(null);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, [scheduleTokenRefresh]);

  const logout = useCallback(async () => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }
    setUser(null);
    setIsAuthenticated(false);
    await oidcService.logout();
  }, []);

  const getAccessToken = useCallback(() => {
    return oidcService.getAccessToken();
  }, []);

  const value = {
    user,
    isAuthenticated,
    isLoading,
    error,
    login,
    logout,
    handleCallback,
    getAccessToken,
  };

  return React.createElement(AuthContext.Provider, { value }, children);
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

