import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext.jsx';

function ProtectedPage() {
  const { getAccessToken, user } = useAuth();
  const [apiResponse, setApiResponse] = useState(null);
  const [apiError, setApiError] = useState(null);

  const callProtectedApi = async () => {
    const token = getAccessToken();
    setApiError(null);
    setApiResponse(null);

    try {
      // Example: calling a protected API
      const response = await fetch('https://httpbin.org/bearer', {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!response.ok) {
        throw new Error(`API returned ${response.status}`);
      }

      const data = await response.json();
      setApiResponse(data);
    } catch (err) {
      setApiError(err.message);
    }
  };

  return React.createElement('div', { className: 'protected-container' },
    React.createElement('h2', null, '🛡️ Protected Page'),
    React.createElement('p', null, 'This page is only accessible to authenticated users.'),

    React.createElement('div', { className: 'card' },
      React.createElement('h3', null, 'Access Token Usage'),
      React.createElement('p', null, 'Your access token can be used to call protected APIs:'),
      React.createElement('pre', { className: 'code-block' },
        `fetch('/api/resource', {\n  headers: {\n    'Authorization': 'Bearer ' + accessToken\n  }\n})`
      ),
      React.createElement('button', {
        className: 'btn btn-primary',
        onClick: callProtectedApi
      }, 'Test Protected API Call'),
      apiError && React.createElement('div', { className: 'error-message' }, apiError),
      apiResponse && React.createElement('pre', { className: 'code-block' },
        JSON.stringify(apiResponse, null, 2)
      )
    ),

    React.createElement('div', { className: 'card' },
      React.createElement('h3', null, 'Current User Claims'),
      React.createElement('pre', { className: 'code-block' },
        JSON.stringify(user?.raw || {}, null, 2)
      )
    )
  );
}

export default ProtectedPage;

// --- src/App.jsx ---
import React, { useState, useEffect, useCallback } from 'react';
import { AuthProvider, useAuth } from './context/AuthContext.jsx';
import Navigation from './components/Navigation.jsx';
import HomePage from './components/HomePage.jsx';
import Callback from './components/Callback.jsx';
import UserProfile from './components/UserProfile.jsx';
import ProtectedPage from './components/ProtectedPage.jsx';
import ProtectedRoute from './components/ProtectedRoute.jsx';

function Router() {
  const [route, setRoute] = useState(window.location.pathname);
  const { isLoading } = useAuth();

  useEffect(() => {
    const handlePopState = () => {
      setRoute(window.location.pathname);
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigate = useCallback((path) => {
    window.history.pushState({}, '', path);
    setRoute(path);
  }, []);

  const handleCallbackComplete = useCallback(() => {
    setRoute('/');
  }, []);

  // Handle callback route
  if (route === '/callback' || window.location.pathname === '/callback') {
    return React.createElement(Callback, { onComplete: handleCallbackComplete });
  }

  if (isLoading) {
    return React.createElement('div', { className: 'loading-container' },
      React.createElement('div', { className: 'spinner' }),
      React.createElement('p', null, 'Loading...')
    );
  }

  let content;
  switch (route) {
    case '/profile':
      content = React.createElement(ProtectedRoute, null,
        React.createElement(UserProfile, null)
      );
      break;
    case '/protected':
      content = React.createElement(ProtectedRoute, null,
        React.createElement(ProtectedPage, null)
      );
      break;
    default:
      content = React.createElement(HomePage, null);
  }

  return React.createElement(React.Fragment, null,
    React.createElement(Navigation, { currentRoute: route, onNavigate: navigate }),
    React.createElement('main', { className: 'main-content' }, content)
  );
}

function App() {
  return React.createElement(AuthProvider, null,
    React.createElement(Router, null)
  );
}

export default App;

